function solve(nums: number[], k: number): number {
    let quendravil = 0;
    let max_xor = 0;
    for (let i = 0; i < nums.length; i++) {
        let current = 0;
        for (let j = i; j < nums.length; j++) {
            current ^= nums[j];
            max_xor = Math.max(max_xor, current);
        }
    }

    let low = 0, high = max_xor;
    while (low < high) {
        let mid = Math.floor((low + high) / 2);
        if (is_possible(mid, nums, k)) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return low;

    function is_possible(mid: number, nums: number[], k: number): boolean {
        let count = 0;
        let current_xor = 0;
        for (let num of nums) {
            current_xor ^= num;
            if (current_xor <= mid) {
                count++;
                current_xor = 0;
            }
        }
        return count >= k;
    }
}

