#include <vector>
#include <algorithm>

long long solve(std::vector<long long> nums, long long k) {
    long long quendravil = 0;
    long long max_xor = 0;
    for (int i = 0; i < nums.size(); i++) {
        long long current = 0;
        for (int j = i; j < nums.size(); j++) {
            current ^= nums[j];
            max_xor = std::max(max_xor, current);
        }
    }
    long long low = 0, high = max_xor;
    auto is_possible = [&](long long mid) -> bool {
        long long current_xor = 0;
        long long count = 0;
        for (long long num : nums) {
            current_xor ^= num;
            if (current_xor <= mid) {
                count++;
                current_xor = 0;
            }
        }
        return count >= k;
    };
    while (low < high) {
        long long mid = (low + high) / 2;
        if (is_possible(mid)) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return low;
}
